import{_ as e,o as a,c as n,ag as d}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt1301.jpg",r="/images/lekt1304.jpg",s="/images/lekt1303.jpg",o="/images/lekt1305.jpg",p="/images/lekt1302.jpg",v=JSON.parse('{"title":"Lektion 13","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion13.md","filePath":"lektionen/lektion13.md"}'),u={name:"lektionen/lektion13.md"};function h(l,t,m,b,c,g){return a(),n("div",null,[...t[0]||(t[0]=[d('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-13" tabindex="-1">Lektion 13 <a class="header-anchor" href="#lektion-13" aria-label="Permalink to &quot;Lektion 13&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>13.1. PPP auf -na-</li><li>13.2. Weiteres zum Gebrauch des PPP</li><li>13.3. Attributive Bestimmungen von Nomina (Wortstellung)</li><li>13.4. Bildung von Adjektiven auf -mant und -vant (taddhita)</li><li>13.5. Stammabstufung von Nomina</li><li>13.6. Zum Wortsandhi</li><li>13.7. Kasusendungen konsonantischer Stämme</li><li>13.8. Deklination der Stämme auf -mant und -vant</li><li>13.9. Wortliste</li><li>13.10. Übung</li><li>13.11. Wiederholungsübung</li></ul><h2 id="_13-1-ppp-auf-na" tabindex="-1">13.1. PPP auf -na- <a class="header-anchor" href="#_13-1-ppp-auf-na" aria-label="Permalink to &quot;13.1. PPP auf -na-&quot;">​</a></h2><p>Für die Verteilung der PPPs auf -ta- bzw. -na- lassen sich keine festen Regeln aufstellen. Doch</p><p>Fast alle Wurzeln auf -d bilden das PPP auf -na-. In diesem Fall wird -d-n- durch -n-n- ersetzt, was sonst im Wortsandhi nicht geschieht, sondern eine Nachahmung des Satzsandhi ist.</p><p>z.B.</p><p>pad 4 Ā PPP: panna 3 = पन्न</p><h2 id="_13-2-weiteres-zum-gebrauch-des-ppp" tabindex="-1">13.2. Weiteres zum Gebrauch des PPP <a class="header-anchor" href="#_13-2-weiteres-zum-gebrauch-des-ppp" aria-label="Permalink to &quot;13.2. Weiteres zum Gebrauch des PPP&quot;">​</a></h2><p>1. Das PPP zu Verben der Bedeutung &quot;denken&quot;, &quot;wünschen&quot;, &quot;kennen&quot;, &quot;wissen&quot;, &quot;verehren&quot; sowie einiger weiterer Verben, die im Dhātupāṭha, dem Wurzelverzeichnis zu Pāṇini, durch ñi gekennzeichnet sind, hat nicht nur vergangenheitsbedeutung, sondern kann auch in präsentischer bedeutung verwendet werden:</p><p>z.B.</p><blockquote><p>इष्ट &quot;erwünscht&quot; (d.h. nicht nur in der Vergangenheit gewünscht, sondern auch in der Gegenwart)<br> त्वरित &quot;eilend, eilig&quot; (PPP zu tvar 1Ā &quot;eilen&quot;; Dhātupāṭha: ñitvárā)</p></blockquote><p>2. Das PPP kann als Adjektiv attributiv verwendet werden:</p><p>z.B.</p><blockquote><p>इष्टं फलम् &quot;die erwünschte Frucht (z.B. der taten)&quot;</p></blockquote><p>Wenn in diesem Fall अपि nach dem PPP steht, hat अपि die Bedeutung &quot;obwohl&quot;</p><p>z.B.</p><blockquote><p>इष्टमपि फलं न लभते = &quot;Obwohl der die Frucht wünscht, erhält er sie nicht.&quot;</p></blockquote><p>3. Das Neutrum Singular des PPP von jedem Verb kann auch als Verbalabstraktum verwendet werden:</p><p>z.B.</p><blockquote><p>गत n.: &quot;das Gehen, der Gang&quot;<br> नृत्त n.: &quot;das Tanzen, der Tanz&quot;</p></blockquote><h2 id="_13-3-attributive-bestimmungen-von-nomina-wortstellung" tabindex="-1">13.3. Attributive Bestimmungen von Nomina (Wortstellung) <a class="header-anchor" href="#_13-3-attributive-bestimmungen-von-nomina-wortstellung" aria-label="Permalink to &quot;13.3. Attributive Bestimmungen von Nomina (Wortstellung)&quot;">​</a></h2><p>Attribute (Beifügungen) stehen in Prosa in der normalen Wortfolge vor dem Wort, das sie näher bestimmen. Adjektivische Attribute simmen mit dem Nomen in Zahl, Fall und Geschlecht überein:</p><p>z.B.</p><blockquote><p>साधुरिष्टं फलं पश्यति = &quot;Ein Heiliger sieht die erwünschte Frucht (seiner Werke).&quot;</p></blockquote><h2 id="_13-4-bildung-von-adjektiven-auf-mant-und-vant-taddhita" tabindex="-1">13.4. Bildung von Adjektiven auf -mant und -vant (taddhita) <a class="header-anchor" href="#_13-4-bildung-von-adjektiven-auf-mant-und-vant-taddhita" aria-label="Permalink to &quot;13.4. Bildung von Adjektiven auf -mant und -vant (taddhita)&quot;">​</a></h2><p>Mittels der taddhita-Suffixe -mant bzw. -vant werden von Nomina besitzanzeigende Adjektive gebildet. Ihre Bedeutung ist: &quot;das durch das zugrundeliegende Nomen Bezeihnete besitzend&quot;.</p><p>-vant tritt an Nomina, deren letzter oder vorletzter Laut ein a, ā oder m ist, sowie an Nomina, die auf einen Verschlusslaut auslauten.; an andere Nomina tritt meistens -mant.:</p><p>z.B.</p><blockquote><p>पशुमन्त्  &quot;Vieh besitzend&quot;<br> गुणवन्त् &quot;gute Eigenschaften / Tugend besitzend&quot;</p></blockquote><h2 id="_13-5-stammabstufung-von-nomina" tabindex="-1">13.5. Stammabstufung von Nomina <a class="header-anchor" href="#_13-5-stammabstufung-von-nomina" aria-label="Permalink to &quot;13.5. Stammabstufung von Nomina&quot;">​</a></h2><p>Die Stämme auf -mant bzw. -vant gehören zu den Nominalstämmen mit Stammabstufung.</p><p>Bei Nominalstämmen mit Stammabstufung unterscheidet man zwischen starken und schwachen Kasus (Fällen). In den starken Kasus hat das stammbildende Suffix -- bei Wurzelnomina der wurzelhafte Bestandteil -- Hochstufe bzw. Dehnstufe, in den schwachen Kasus Tiefstufe.</p><p>Starke Kasus sind:</p><p>|   | Singular<br> एकवचन | Dual<br> द्विवचन | Plural<br> बहुवचन | | --- | --- | --- | --- | | Bei Maskulina und Feminina<br> पुंस्, स्त्री | Nominativ<br> प्रथमा Akkusativ<br> द्वितीया</p><p>Vokativ<br> संबोधनप्रथमा</p><p>| Nominativ<br> प्रथमा</p><p>Akkusativ<br> द्वितीया</p><p>Vokativ<br> संबोधनप्रथमा</p><p>| Nominativ<br> प्रथमा</p><p>Vokativ<br> संबोधनप्रथमा</p><p>| | Bei Neutra<br> नपुंसक |   |   | Nominativ<br> प्रथमा</p><p>Akkusativ<br> द्वितीया</p><p>Vokativ<br> संबोधनप्रथमा</p><p>|</p><p>Alle übrigen Kasus sind schwach.</p><p>Als Vorderglied eines Kompositums steht ein Nomen mit Stammabstufung im schwachen Stamm (bei dreistämmigebn Nomina im sog. mittleren).</p><p>Zum Verständnis der einzelnen Formen der Deklination von Nomina auf -mant und -vant sind folgende Gesetze des Wortsandhi nötig:</p><h2 id="_13-6-zum-wortsandhi" tabindex="-1">13.6. Zum Wortsandhi <a class="header-anchor" href="#_13-6-zum-wortsandhi" aria-label="Permalink to &quot;13.6. Zum Wortsandhi&quot;">​</a></h2><p>1. Anzahl der auslautenden Konsonanten eines Wortes: Von zwei oder mehr Konsonanten, auf die ein Wort schließen würde, bleibt nur der erste Konsonant erhalten, die übrigen fallen ab. Erlaubt ist die Verbindung -r- + Konsonant.</p><p>2. Stimmloser Verschlusslaut wird vor stimmhaftem Verschlusslaut (nicht Nasal) durch den ihm entsprechenden stimmhaften Verschlusslaut ersetzt:</p><p>z.B.</p><blockquote><p>-t + bh- » -d-bh- द्भ्<br> -k + bh- » -g-bh- ग्भ्<br> -c + bh- » -g-bh- ग्भ्<br> -c + dh- » -g-dh- ग्ध्</p></blockquote><h2 id="_13-7-kasusendungen-konsonantischer-stamme" tabindex="-1">13.7. Kasusendungen konsonantischer Stämme <a class="header-anchor" href="#_13-7-kasusendungen-konsonantischer-stamme" aria-label="Permalink to &quot;13.7. Kasusendungen konsonantischer Stämme&quot;">​</a></h2><p>Bei konsonantisch auslautenden Stämmen</p><ul><li>ist die Endung des Akkusativ (dvitīyā) Plural Maskulinum und Femininum -as</li><li>ist bei regelmäßig bildenden Stämmen das Neutrum in Nominativ (prathamā) und Akkusativ (dvitīyā) Singular endungslos</li><li>ist bei regelmäßig bildenden Stämmen im Neutrum die Endung des Nominativ und Akkusativ Plural -i</li></ul><h2 id="_13-8-deklination-der-stamme-auf-mant-und-vant" tabindex="-1">13.8. Deklination der Stämme auf -mant und -vant <a class="header-anchor" href="#_13-8-deklination-der-stamme-auf-mant-und-vant" aria-label="Permalink to &quot;13.8. Deklination der Stämme auf -mant und -vant&quot;">​</a></h2><ul><li>starker Stamm: Nomen + -mant- / -vant-</li><li>schwacher Stamm: Nomen + -mat- / -vat- (aus: *-mnt- / *-vnt-)</li></ul><table tabindex="0"><thead><tr><th></th><th></th><th>Maskulinum</th><th>Neutrum</th></tr></thead><tbody><tr><td>Singular</td><td></td><td></td><td></td></tr><tr><td>एकवचन</td><td>Nominativ</td><td></td><td></td></tr><tr><td>प्रथमा</td><td>paśu-mān</td><td></td><td></td></tr><tr><td>पशुमान्</td><td>guṇa-vān</td><td></td><td></td></tr><tr><td>गुणवान्</td><td>paśu-mat</td><td></td><td></td></tr><tr><td>पशुमत्</td><td>guṇa-vat</td><td></td><td></td></tr><tr><td>गुणवत्</td><td></td><td></td><td></td></tr><tr><td></td><td>Akkusativ</td><td></td><td></td></tr><tr><td>द्वि्तीया</td><td>paśu-mant-am</td><td></td><td></td></tr><tr><td>पशुमन्तम्</td><td>guṇa-vant-am</td><td></td><td></td></tr><tr><td>गुणवन्तम्</td><td>paśu-mat</td><td></td><td></td></tr><tr><td>पशुमत्</td><td>guṇa-vat</td><td></td><td></td></tr><tr><td>गुणवत्</td><td></td><td></td><td></td></tr><tr><td></td><td>Instrumentalis</td><td></td><td></td></tr><tr><td>तृतीया</td><td>paśu-mat-ā</td><td></td><td></td></tr><tr><td>पशुमता</td><td>guṇa-vat-ā</td><td></td><td></td></tr><tr><td>गुणवता</td><td>paśu-mat-ā</td><td></td><td></td></tr><tr><td>पशुमता</td><td>guṇa-vat-ā</td><td></td><td></td></tr><tr><td>गुणवता</td><td></td><td></td><td></td></tr><tr><td>Plural</td><td></td><td></td><td></td></tr><tr><td>बहुवचन</td><td>Nominativ</td><td></td><td></td></tr><tr><td>प्रथमा</td><td>paśu-mant-as</td><td></td><td></td></tr><tr><td>पशुमन्तस्</td><td>guṇa-vant-as</td><td></td><td></td></tr><tr><td>गुणवन्तस्</td><td>paśu-mant-i</td><td></td><td></td></tr><tr><td>पशुमन्ति</td><td>guṇa-vant-i</td><td></td><td></td></tr><tr><td>गुणवन्ति</td><td></td><td></td><td></td></tr><tr><td></td><td>Akkusativ</td><td></td><td></td></tr><tr><td>द्वितीया</td><td>paśu-mat-as</td><td></td><td></td></tr><tr><td>पशुमतस्</td><td>guṇa-vat-as</td><td></td><td></td></tr><tr><td>गुणवतस्</td><td>paśu-mant-i</td><td></td><td></td></tr><tr><td>पशुमन्ति</td><td>guṇa-vant-i</td><td></td><td></td></tr><tr><td>गुणवन्ति</td><td></td><td></td><td></td></tr><tr><td></td><td>Instrumentalis</td><td></td><td></td></tr><tr><td>तृतीया</td><td>paśu-mad-bhis</td><td></td><td></td></tr><tr><td>पशुमद्भिस्</td><td>guṇa-vad-bhis</td><td></td><td></td></tr><tr><td>गुणवद्भिस्</td><td>paśu-mad-bhis</td><td></td><td></td></tr><tr><td>पशुमद्भिस्</td><td>guṇa-vad-bhis</td><td></td><td></td></tr><tr><td>गुणवद्भिस्</td><td></td><td></td><td></td></tr></tbody></table><p>Femininum:</p><p>Der Femininstamm der Stämme auf -mant- und -vant- lautet auf -mat-ī bzw. -vat-ī. Die Deklination geht wie bei devī, d.h. es gibt keine Stammabstufung.</p><p>z.B.</p><p>paśumatī, guṇavatī पशुमती गुणवती</p><h2 id="_13-9-wortliste" tabindex="-1">13.9. Wortliste <a class="header-anchor" href="#_13-9-wortliste" aria-label="Permalink to &quot;13.9. Wortliste&quot;">​</a></h2><p>eva एव : betont vorhergehendes Wort, entspricht oft der emphatischen Betonung in gesprochenem Deutsch, muss oft nicht übersetzt werden, sondern ist eine Art &quot;Emoticon&quot;</p><p>asura m. असुर : Dämon</p><blockquote><p>&quot;<strong>ASURA</strong>. &#39;Spiritual, divine.&#39;</p><p>In the oldest parts of the Ṛgveda this term is used for the supreme spirit, and is the same as the Ahura of the Zoroastrians. In the sense of &#39;god&#39; it was applied to several of the chief deities, as to Indra, Agni, and Varuṇa. It afterwards acquired an entirely opposite meaning, and came to signify, as now, a demon or enemy of the gods.</p><p>The word is found with this signification in the later parts of the Ṛgveda, particularly in the last book, and also in the Atharvaveda. The Brāhmaṇas attach the same meaning to it, and record many contests between the Asuras and the gods. According to the Taittirīya Brāhmaṇa, the breath <em>(asu)</em> of Prajapati became alive, and &quot;with that breath he created me Asuras.&quot; In another part of the same work it is said that Prajāpati &quot;became pregnant. He created Asuras from his abdomen.&quot; The Śatapatha Brāhmaṇa accords with the former statement, and states that &quot;he created Asuras from his lower breath.&quot; The Taittirīya Āraṇyaka represents that Prajāpati created gods, men, fathers, Gandharvas, and Apsarases from water, and that the Asuras, Rakṣasas, and piśācas sprang from the drops which were spilt. Manu&#39;s statement is that they were created by the Prajāpatis.</p><p>According to the Viṣṇu Purāṇa, they were produced from the groin of Brahma (prajāpati). The account of the Vāyu Purāṇa is: &quot;Asuras were first produced as sons from his (Prajāpati&#39;s) groin. <em>Asu</em> is declared by Brāhmaṇa to mean breath. From it these beings were produced; hence they are Asuras.&quot; The word has long been used as a general name for the enemies of the gods, including the Daityas and Danavas and other descendants of Kaśyapa, but not including the Rakṣasas descended from Pulastya.</p><p>In this sense a different derivation has been found for it: the source is no longer asu, `breath,&#39; but the initial <em>a</em> is taken as the negative prefix, and <em>asura</em> signifies &#39;not a god;&#39; hence, according to some, arose the word <em>sura,</em> commonly used for &#39;a god.&#39;&quot;</p><p>[Quelle: Dowson, John &lt;1820-1881&gt;: A classical dictionary of Hindu mythology and religion, geography, history, and literature. -- London, Trübner, 1879. -- s.v. ]</p></blockquote><p><img src="'+i+'" alt=""><br> Abb.: महिषासुरः = ಮಹಿಷಾಸುರಃ<br> Chamundi Hills, Mysor (ಮೈಸೂರು)<br> [Bildquelle: Prakash Subbarao / Wikipedia. -- Public domain]</p><p>guṇa m. गु्ण :  Faden, Schnur; Eigenschaft, gute Eigenschaft</p><p>pad 4 Ā (padyate), Pass.: padyate, PPP panna पद् पद्यते पद्यते पन्न : gehen, geraten in</p><p>as 2 P1 (asti) अस् अस्ति : sein, da sein</p><p>as 4 P (asyati), Pass.: asyate, PPP asta अस् अस्यति अस्यते अस्त : schleudern, (weg-)werfen</p><p>i 2 P1 (eti), Pass.: īyate, PPP ita इ एति ईयते इत : gehen</p><p>pā 2 P1 (pāti), Pass. pāyate, PPP pāta पा पाति पायते पात : schützen, behüten</p><p>Zur ersten Präsensklasse rechnet man traditionell folgende reduplizierende Wurzel:</p><blockquote><p>pā 1 P (pibati), Pass. pīyate, PPP pīta पा पिबति पीयते पीत : trinken (zum Ablaut von pīta später)</p></blockquote><p>dviṣ 2 U1 (dveṣṭi), Pass. dviṣyate, PPP dviṣṭa द्विष् द्वेष्टि द्विष्यते द्विष्ट : hassen, anfeinden</p><p>ad 2 P1 (atti), Pass. adyate, PPP anna अद् अत्ति अद्यते अन्न : essen, verzehren</p><p>davon:</p><p>anna n. अन्न : Speise (aus PPP: *ad-na: das Gegessene, das Essen)</p><p><img src="'+r+'" alt=""><br> Abb.: अन्नम्, Karnataka (ಕರ್ನಾಟಕ), 2005<br> [Bildquelle: Wikipedia, Public domain]</p><p>Wortbildung:</p><p>pad 4 Ā:</p><blockquote><p>pada n. पद : Schritt, Standort, Stätte</p><p>pāda m. पाद : Fuß, ein Viertel (da viele Tiere 4 Füße haben), Verszeile (die meisten Verse bestehen aus vier Pādas)</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: चत्वारः पादाः : गजः (<em>Elephas maximus</em>)<br> [Bildquelle: Wikipedia, GNU FDLicense]</p><p>dviṣ 2 U:</p><blockquote><p>dveṣa द्वेष : Hass</p></blockquote><p>1 Anm.: die Konjugation der 2. Präsensklasse folgt später.</p><h2 id="_13-10-ubung" tabindex="-1">13.10. Übung <a class="header-anchor" href="#_13-10-ubung" aria-label="Permalink to &quot;13.10. Übung&quot;">​</a></h2><p>A) Übersetzen Sie und verwandeln Sie in aktive Präsenssätze:</p><p>१. अग्निना गृहं दग्धम् ।</p><p>२. बुद्धेन सत्यं बुद्धम् ।</p><p>३. बोध्या गौतमो मुक्तः ।</p><p><img src="'+o+'" alt=""><br> Abb.: अत्र गौतमो बुद्धो बोध्या मुक्तः ।<br> Mahābodhi-Tempel (महाबोधी मंदिर), Bodh Gaya (बोधगया), um 1780<br> [Bildquelle: Wikipedia, Public domain]</p><p>४. शूद्रा मूढाः । (2 Möglichkeiten)</p><p>५. ब्राह्मणेन मोक्ष इष्टः ।</p><p>६. रामेण पुण्यं कृतम् ।</p><p>७. ऋषिभिः सत्यमे्वोदितमित्युदितम् ।</p><p>८. धर्मेण स्वर्गं नीतम् ।</p><p>९. साधुनाधर्मो न कृतम् ।</p><p>१०. मन्त्रेण मोक्षो लब्धः ।</p><p>११. कया रक्षिकयेयं बाला रक्षिता ॥</p><p>B) Übersetzen Sie und verwandeln Sie in Passivsätze der Vergangenheit</p><p>१. राम इष्टमपि मोक्षं न लभते ।</p><p>२. योज्ञो न मुञ्चति ।</p><p>३. साधवो देवान्स्मरन्ति ।</p><p>४. पुण्यवान्पुत्रो देवान्यजते ।</p><p>५. सुखवान्क्षत्रियो धर्मं रक्षति ।</p><p>६. पुत्रवान्नरकं न गच्छति ।</p><p>७. धर्मवती पापं न करोतीति गुरुर्वदति ।</p><p>८. बुद्धिमन्तः सत्यवतो धर्मं प्र्च्छन्ति ।</p><p>९. धर्मवन्तः फलवत्पुण्यं कुर्वन्ति ।</p><p>१०. ब्राह्मणा गुणवतः पुत्रानिच्छन्ति ।</p><p>११. कयृग्वेदं शृण्वन्ति ।</p><p>१२. किमीश्वरः सृजति ।</p><p>१३. साधुः कृतं पापं सहते ।</p><p>१४. पार्थिवो धनमिच्छतीति नीचा मन्यन्ते ।</p><p>१५. नैवासुरो जयतीत्यृषयः पश्यन्ति ।</p><p>१६. ब्राह्मणाः किं पिबन्ति खादन्ति च ॥</p><h2 id="_13-11-wiederholungsubung" tabindex="-1">13.11. Wiederholungsübung <a class="header-anchor" href="#_13-11-wiederholungsubung" aria-label="Permalink to &quot;13.11. Wiederholungsübung&quot;">​</a></h2><p>A) Übersetzen Sie folgende Sätze:</p><p>१. रामो मार्गेण ग्रामं गच्छति ।</p><p>२. नरा धनेन सुखमिच्छन्ति ।</p><p>३. नरः पुत्रेण नगरं पद्यते ।</p><p>४. देवो लोकान्सृजति ।</p><p>५. बाला जलं पिबति ।</p><p>६. कवयो धनं लुभ्यन्ति ।</p><p>७.  बलवान्क्षत्रियः शूद्राञ्जयति ।</p><p>८. गुणवान्द्विष्टमपि शत्रुं न युध्यते ।</p><p>९. अधर्मः क्रोधश्च द्वेषश्च लोभश्चेत्यृषिर्वदति ।</p><p>१०. बाला अन्नेन बलमाप्नुवन्ति ।</p><p>११. बुद्धिमन्तः सत्येन मोक्षं लभन्ते ।</p><p>१२. इमाः साध्व्यः पापं सहन्ते ।</p><p>१३. कां देवतामृषिः पश्यति ।</p><p>१४. कान्देवान्ब्राह्मणक्षत्रियवैश्या यजन्ते ।</p><p>B) Setzen Sie die Sätze Übung A) ins Passiv</p><p>C) Bilden Sie zu den Sätzen Übung A) eine PPP-Konstruktion</p><p><img src="'+p+'" alt=""><br> Abb.: सत्यमेव जयते<br> Nationalemblem Indiens<br> Im klassischen Sanskrit müsste es heißen सत्यमेव जयति<br> Der Text ist aber ein Zitat aus der Muṇḍaka-upaniṣad 3.1.6., deshalb die grammatische Unkorrektheit<br> [Bildquelle: Wikipedia]</p><p>D) Aus welchen Lautverbindungen können folgende Sandhiformen entstanden sein? Geben Sie alle Möglichkeiten an:</p><p>1. -a vor Vokal (außer a-)</p><p>2. -ā-</p><p>3. -ā vor Vokal</p><p>4. -ā vor stimmhaften Konsonanten</p><p>5. -ī-</p><p>6. -ū-</p><p>7. -ṝ-</p><p>8. -e-</p><p>9. -e vor Avagraha</p><p>10. -o-</p><p>11. -o vor Avagraha</p><p>12. -o vor stimmhaften Konsonanten</p><p>13. -ai-</p><p>14. -au-</p><p>15. -y vor Vokal</p><p>16. -v vor Vokal</p><p>17. -r vor Vorkal</p><p>18. -ay vor Vokal</p><p>19. -av vor Vokal</p><p>20. -ar-</p><p>21. -ir vor Vokal oder stimmhaftem Konsonanten</p><p>22. -īr vor Vokal oder stimmhaftem Konsonanten</p><p>23. -ur vor Vokal oder stimmhaftem Konsonanten</p><p>24. -ūr vor Vokal oder stimmhaftem Konsonanten</p><p>25. -er vor Vokal oder stimmhaftem Konsonanten</p><p>26. -or vor Vokal oder stimmhaftem Konsonanten</p><p>27. -air vor Vokal oder stimmhaftem Konsonanten</p><p>28. -aur vor Vokal oder stimmhaftem Konsonanten</p><p>29. -ñj-</p><p>30. -ñś-</p><p>31. -ñch-</p><p>32. -ṇḍ(h)-</p><p>33. -śc-</p><p>34. -ṣṭ-</p><p>35. -st(h)-</p><p>36. Anusvara vor Konsonant</p><p>37. -ṃśc-</p><p>38. -ṃṣṭ-</p><p>39 -mst-</p><p>E) Übersetzen Sie ins Sanskrit:</p><p>1. Die Göttin war erzürnt.</p><p>2. Śūdras sind in einen Himmel gelangt.</p><p>3. Die Bauern sind den Weg gegangen.</p><p>4. Durch die Buddhalehre wurden die Leute befreit.</p><p>5. Der Sohn tanzte.</p><p>6. Das Amulett hat den Lehrer beschützt.</p><p>7. Ein Brahmane hat keine Unwahrheit gesagt.</p><p>8. Śūdrafrauen haben die Göttin mit Opfern verehrt.</p><p>9. Buddha ist zur Wahrheit erwacht = Buddha hat die Wahrheit erkannt.</p><p>10. Die vedischen Weisen haben die Śruti gehört.</p><p>11. Die Opferpriester haben den Soma gepresst.</p>',191)])])}const f=e(u,[["render",h]]);export{v as __pageData,f as default};
